namespace HomeMesh.WebApi.Admin;

public static class AdminConsoleHtml
{
    public const string Content = """
<!doctype html><html lang="zh-CN"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>HomeMesh Admin</title><style>
body{margin:0;background:#07111f;color:#e6eefc;font-family:system-ui,-apple-system,Segoe UI,sans-serif}.layout{display:grid;grid-template-columns:230px 1fr;min-height:100vh}aside{background:#0b1728;border-right:1px solid #263a56;padding:24px}main{padding:26px}.logo{font-size:24px;font-weight:800;margin-bottom:28px}.nav{color:#8ea4c2;margin:12px 0;text-decoration:none;display:block}.cards{display:grid;grid-template-columns:repeat(4,1fr);gap:14px}.grid2{display:grid;grid-template-columns:1fr 1fr;gap:14px}.card{background:#102039;border:1px solid #263a56;border-radius:18px;padding:16px;margin-bottom:14px}.metric{font-size:26px;font-weight:800}button,input,select{border-radius:10px;border:1px solid #2d4568;background:#0c1a30;color:#e6eefc;padding:9px 11px}button{background:#0f766e;border:0;font-weight:700;cursor:pointer}button.secondary{background:#1e3a5f}button.danger{background:#7f1d1d}table{width:100%;border-collapse:collapse}td,th{padding:10px;border-bottom:1px solid #263a56;text-align:left}.row{display:flex;gap:10px;flex-wrap:wrap;margin:10px 0}.muted{color:#8ea4c2}.log{white-space:pre-wrap;color:#8ea4c2}.pill{border-radius:999px;padding:4px 8px;background:#173451;color:#5eead4;font-size:12px}.warning{border:1px solid #f59e0b;background:#3b2f14;color:#fef3c7;border-radius:12px;padding:10px;margin:10px 0}.auth{max-width:480px;margin:10vh auto}.hidden{display:none}@media(max-width:1000px){.layout{grid-template-columns:1fr}aside{display:none}.cards,.grid2{grid-template-columns:1fr}}
</style></head><body>
<div id="auth" class="auth card hidden"><h1 id="authTitle">HomeMesh</h1><p id="authHint" class="muted"></p><div class="row"><input id="authUser" placeholder="用户名"><input id="authPass" type="password" placeholder="密码"></div><button id="authButton" onclick="submitAuth()">继续</button><div id="authLog" class="log"></div></div>
<div id="app" class="layout hidden"><aside><div class="logo">HomeMesh</div><div class="nav">控制台</div><div class="nav">网络</div><div class="nav">成员</div><div class="nav">审计日志</div><a class="nav" href="/swagger">Swagger</a><button class="secondary" onclick="logout()">退出登录</button></aside><main>
<h1>HomeMesh 管理控制台</h1><p class="muted">Home SD-WAN Controller · <span id="who">-</span></p>
<div class="cards"><div class="card">Health<div id="health" class="metric">-</div></div><div class="card">Networks<div id="networkCount" class="metric">0</div></div><div class="card">Members<div id="memberCount" class="metric">0</div></div><div class="card">Sync Errors<div id="syncErrors" class="metric">0</div></div></div>
<div class="card"><h2>网络</h2><div class="row"><input id="name" placeholder="网络名称"><input id="cidr" placeholder="10.10.0.0/24"><select id="provider"><option value="Demo">Demo 演示</option><option value="ZeroTier">ZeroTier</option></select><label><input id="createAutoApprove" type="checkbox"> 自动审核</label><button onclick="createNetwork()">创建网络</button><button class="secondary" onclick="downloadPlantFile()">下载 plant 文件</button><button class="secondary" onclick="refreshAll()">刷新</button></div><div id="providers" class="muted">Providers: -</div><div id="providerHint" class="warning hidden"></div><select id="net" onchange="loadSelected()"></select><table><thead><tr><th>名称</th><th>CIDR</th><th>自动审核</th><th>状态</th></tr></thead><tbody id="netRows"></tbody></table></div>
<div class="grid2"><div class="card"><h2>Easy Setup</h2><div class="row"><input id="easyCidr" placeholder="CIDR"><input id="easyPoolStart" placeholder="IP池开始"><input id="easyPoolEnd" placeholder="IP池结束"></div><div class="row"><label><input id="easyAutoAssign" type="checkbox" checked> 自动分配地址</label><label><input id="easyAutoApprove" type="checkbox"> 自动审核成员</label><input id="easyDnsDomain" placeholder="DNS域，可空"><input id="easyDnsServers" placeholder="DNS服务器，逗号分隔"><button onclick="easySetup()">应用快速配置</button></div></div><div class="card"><h2>同步状态</h2><div id="memberSyncState" class="muted">成员同步：-</div><div id="configSyncState" class="muted">配置同步：-</div><div class="row"><button onclick="syncMembers()">同步成员</button><button onclick="syncConfig()">同步配置</button></div></div></div>
<div class="grid2"><div class="card"><h2>路由 / IP池 / DNS</h2><div class="row"><input id="route" placeholder="路由CIDR"><input id="routeVia" placeholder="Via，可空"><button onclick="addRoute()">添加路由</button></div><div class="row"><input id="poolStart" placeholder="IP池开始"><input id="poolEnd" placeholder="IP池结束"><button onclick="addPool()">添加IP池</button></div><div class="row"><input id="dnsDomain" placeholder="DNS域"><input id="dnsServers" placeholder="DNS服务器，逗号分隔"><button onclick="saveDns()">保存DNS</button></div><h3>路由</h3><table><tbody id="routeRows"></tbody></table><h3>IP池</h3><table><tbody id="poolRows"></tbody></table></div><div class="card"><h2>成员</h2><table><thead><tr><th>ID</th><th>名称</th><th>授权</th><th>在线</th><th>IP地址</th><th>操作</th></tr></thead><tbody id="memberRows"></tbody></table></div></div>
<div class="grid2"><div class="card"><h2>审计日志</h2><table><thead><tr><th>时间</th><th>类型</th><th>消息</th></tr></thead><tbody id="auditRows"></tbody></table></div><div class="card"><h2>操作日志</h2><div id="log" class="log">Ready.</div></div></div>
</main></div>
<script>
let nets=[],mode='login';const q=id=>document.getElementById(id);const log=m=>q('log').textContent=new Date().toLocaleTimeString()+' '+m+'\n'+q('log').textContent;const authLog=m=>q('authLog').textContent=m;async function api(p,o){const r=await fetch(p,{headers:{'Content-Type':'application/json'},...o});if(r.status===401){showLoginExpired();throw new Error('登录已过期，请重新登录。')}if(!r.ok)throw new Error(await r.text());return r.status===204?null:await r.json()}function current(){return q('net').value}function showLoginExpired(){mode='login';q('authTitle').textContent='登录 HomeMesh';q('authHint').textContent='登录已过期，请重新登录。';q('authButton').textContent='登录';showAuth()}async function boot(){try{const s=await api('/api/auth/status');if(!s.initialized){mode='setup';q('authTitle').textContent='初始化 HomeMesh';q('authHint').textContent='创建第一个管理员账号。';q('authButton').textContent='创建管理员';showAuth();return}if(!s.authenticated){mode='login';q('authTitle').textContent='登录 HomeMesh';q('authHint').textContent='请输入管理员账号。';q('authButton').textContent='登录';showAuth();return}q('who').textContent=s.user.username+' / '+s.user.role;showApp();await refreshAll()}catch(e){authLog('启动失败 '+e.message);showAuth()}}function showAuth(){q('auth').classList.remove('hidden');q('app').classList.add('hidden')}function showApp(){q('auth').classList.add('hidden');q('app').classList.remove('hidden')}async function submitAuth(){try{const username=q('authUser').value,password=q('authPass').value;if(mode==='setup'){await api('/api/setup/admin',{method:'POST',body:JSON.stringify({username,password})})}await api('/api/auth/login',{method:'POST',body:JSON.stringify({username,password})});await boot()}catch(e){authLog('失败 '+e.message)}}async function logout(){await api('/api/auth/logout',{method:'POST'});location.reload()}async function refreshAll(){try{q('health').textContent=(await api('/health')).status;const ps=await api('/api/providers');renderProviders(ps);const summary=await api('/api/dashboard/summary');q('networkCount').textContent=summary.networkCount;q('memberCount').textContent=summary.memberCount;q('syncErrors').textContent=summary.errorSyncCount;nets=await api('/api/networks');q('net').innerHTML=nets.map(n=>`<option value="${n.id}">${n.name}</option>`).join('');q('netRows').innerHTML=nets.map(n=>`<tr><td>${n.name}</td><td>${n.cidr||'-'}</td><td>${n.autoApproveMembers?'是':'否'}</td><td><span class="pill">${n.status}</span></td></tr>`).join('');await Promise.all([loadSelected(),loadAudits()]);log('刷新完成')}catch(e){log('错误 '+friendlyError(e))}}function renderProviders(ps){q('providers').textContent='Providers: '+(ps.map(x=>x.providerName+':'+x.status).join(',')||'-');const bad=ps.find(x=>x.providerName==='ZeroTier'&&x.status!=='Healthy');if(!bad){q('providerHint').classList.add('hidden');return}q('providerHint').classList.remove('hidden');q('providerHint').textContent=`ZeroTier 状态为 ${bad.status}。如只是演示 MVP，请选择 Demo Provider 创建网络；如要连接真实 ZeroTier，请检查 ZeroTier One、ApiBaseUrl 和 authtoken.secret。${bad.message||''}`}function friendlyError(e){const m=e&&e.message?e.message:String(e);if(m.includes('Provider')||m.includes('ZeroTier')||m.includes('Connection')||m.includes('refused'))return 'Provider 连接失败。演示模式请选择 Demo；真实环境请检查 ZeroTier 服务、ApiBaseUrl 和 token 挂载。详情：'+m;return m}async function createNetwork(){await api('/api/networks',{method:'POST',body:JSON.stringify({name:q('name').value,cidr:q('cidr').value||null,provider:q('provider').value,private:true,autoApproveMembers:q('createAutoApprove').checked})});await refreshAll()}function downloadPlantFile(){const id=current();if(!id){log('请先选择网络');return}window.location.href=`/api/networks/${id}/plant-file`}async function loadSelected(){const id=current();if(!id)return;await Promise.all([loadMembers(),loadRoutes(),loadPools(),loadSyncStates()])}function parseIps(v){if(!v)return[];try{return JSON.parse(v)}catch{return[]}}async function loadMembers(){const ms=await api(`/api/networks/${current()}/members`);q('memberRows').innerHTML=ms.map(m=>{const ips=parseIps(m.ipAssignmentsJson).join(',');return `<tr><td>${m.providerMemberId}</td><td>${m.name||'-'}</td><td>${m.authorized?'是':'否'}</td><td>${m.online?'是':'否'}</td><td><input id="ip_${m.id}" value="${ips}" placeholder="10.10.0.10"></td><td><button class="secondary" onclick="assignIp('${m.id}')">分配IP</button><button class="secondary" onclick="setAuth('${m.id}',${!m.authorized})">${m.authorized?'取消授权':'授权'}</button></td></tr>`}).join('')}async function loadRoutes(){const rs=await api(`/api/networks/${current()}/routes`);q('routeRows').innerHTML=rs.map(r=>`<tr><td>${r.target}</td><td>${r.via||'-'}</td><td>${r.enabled?'启用':'停用'}</td><td><button class="danger" onclick="deleteRoute('${r.id}')">删除</button></td></tr>`).join('')}async function loadPools(){const ps=await api(`/api/networks/${current()}/ip-pools`);q('poolRows').innerHTML=ps.map(p=>`<tr><td>${p.ipRangeStart}</td><td>${p.ipRangeEnd}</td><td><button class="danger" onclick="deletePool('${p.id}')">删除</button></td></tr>`).join('')}async function loadSyncStates(){const id=current();const ms=await api(`/api/networks/${id}/members/sync-state`);const cs=await api(`/api/networks/${id}/config/sync-state`);q('memberSyncState').textContent='成员同步：'+fmtState(ms);q('configSyncState').textContent='配置同步：'+fmtState(cs)}async function loadAudits(){const logs=await api('/api/audit-logs');q('auditRows').innerHTML=logs.slice(0,20).map(x=>`<tr><td>${fmtTime(x.createdAt)}</td><td>${x.type}</td><td>${x.message}</td></tr>`).join('')}function fmtTime(v){return v?new Date(v).toLocaleString():'-'}function fmtState(xs){if(!xs||!xs[0])return '-';const x=xs[0];return `${x.status} ${fmtTime(x.lastSyncAt)} ${x.lastError||''}`}async function easySetup(){const servers=q('easyDnsServers').value.split(',').map(x=>x.trim()).filter(Boolean);await api(`/api/networks/${current()}/easy-setup`,{method:'POST',body:JSON.stringify({cidr:q('easyCidr').value,ipPoolStart:q('easyPoolStart').value,ipPoolEnd:q('easyPoolEnd').value,enableAutoAssign:q('easyAutoAssign').checked,autoApproveMembers:q('easyAutoApprove').checked,dnsDomain:q('easyDnsDomain').value||null,dnsServers:servers})});log('快速配置已应用');await loadSelected()}async function addRoute(){await api(`/api/networks/${current()}/routes`,{method:'POST',body:JSON.stringify({target:q('route').value,via:q('routeVia').value||null})});log('路由已添加');await loadRoutes()}async function addPool(){await api(`/api/networks/${current()}/ip-pools`,{method:'POST',body:JSON.stringify({ipRangeStart:q('poolStart').value,ipRangeEnd:q('poolEnd').value})});log('IP池已添加');await loadPools()}async function deleteRoute(id){if(!confirm('确认删除该路由？'))return;await api(`/api/networks/${current()}/routes/${id}`,{method:'DELETE'});log('路由已删除');await loadRoutes()}async function deletePool(id){if(!confirm('确认删除该 IP 池？'))return;await api(`/api/networks/${current()}/ip-pools/${id}`,{method:'DELETE'});log('IP池已删除');await loadPools()}async function saveDns(){const servers=q('dnsServers').value.split(',').map(x=>x.trim()).filter(Boolean);await api(`/api/networks/${current()}/dns`,{method:'PUT',body:JSON.stringify({domain:q('dnsDomain').value||null,servers})});log('DNS已保存')}async function syncMembers(){const r=await api(`/api/networks/${current()}/members/sync`,{method:'POST'});log(`成员同步 ${r.status}，自动授权 ${r.autoApprovedMemberCount||0} 个`);await refreshAll()}async function syncConfig(){const r=await api(`/api/networks/${current()}/config/sync`,{method:'POST'});log('配置同步 '+r.status);await refreshAll()}async function setAuth(id,value){await api(`/api/networks/${current()}/members/${id}/${value?'authorize':'deauthorize'}`,{method:'POST'});log(value?'已授权':'已取消授权');await loadMembers()}async function assignIp(id){const ips=q('ip_'+id).value.split(',').map(x=>x.trim()).filter(Boolean);await api(`/api/networks/${current()}/members/${id}`,{method:'PATCH',body:JSON.stringify({ipAssignments:ips})});log('IP地址已分配');await loadMembers()}boot();
</script></body></html>
""";
}
